def write_text(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content.rstrip() + "\n", encoding="utf-8")


def read_markdown(relative_path: str) -> str:
    path = DOC_ROOT / relative_path
    text = path.read_text(encoding="utf-8")
    lines = text.splitlines()
    if lines and lines[0].startswith("<!-- Auto-generated by documentation/tools/dissect_report.py"):
        text = "\n".join(lines[2:])
    return text.strip()


def retarget_links(text: str, source_relative_path: str, output_path: Path) -> str:
    source_path = DOC_ROOT / source_relative_path

    def replacer(match: re.Match[str]) -> str:
        target = match.group(1)
        if target.startswith(("http://", "https://", "#", "/")):
            return match.group(0)
        resolved = (source_path.parent / target).resolve()
        return f"]({Path(os.path.relpath(resolved, start=output_path.parent)).as_posix()})"

    return re.sub(r"\]\(([^)]+)\)", replacer, text)


def read_for_draft(relative_path: str, output_path: Path) -> str:
    return retarget_links(read_markdown(relative_path), relative_path, output_path)


def cleanup_spacing(text: str) -> str:
    text = re.sub(r"\n{3,}", "\n\n", text.strip())
    return text + "\n"


def sectionize_source(text: str) -> str:
    return re.sub(r"(?m)^# ", "## ", text)


def nest_standalone_doc(text: str) -> str:
    return re.sub(r"(?m)^(#{1,6}) ", lambda m: "#" + m.group(1) + " ", text)


def rel_link(from_path: Path, target_relative_to_doc_root: str) -> str:
    target = DOC_ROOT / target_relative_to_doc_root
    return Path(os.path.relpath(target, start=from_path.parent)).as_posix()


def add_mermaid_links(text: str, draft_path: Path) -> str:
    lines: list[str] = []
    for line in text.splitlines():
        lines.append(line)
        match = re.match(r"^\*Figure\s+(\d+\.\d+)[.:].*\*$", line.strip())
        if match:
            figure_key = match.group(1)
            mermaid_target = FIGURE_TO_MERMAID.get(figure_key)
            if mermaid_target:
                link = rel_link(draft_path, mermaid_target)
                lines.append(f"Mermaid source: [`{Path(mermaid_target).name}`]({link})")
    return "\n".join(lines)


def clean_front_matter() -> str:
    output_path = DOC_ROOT / "01-front-matter/front-matter-draft.md"
    cover = read_for_draft("01-front-matter/01-cover-and-title-page/report-source.md", output_path)
    ack = read_for_draft("01-front-matter/02-acknowledgement/report-source.md", output_path)
    abstract = read_for_draft("01-front-matter/04-abstract/report-source.md", output_path)
    toc_lists = read_for_draft("01-front-matter/03-table-of-contents-and-lists/report-source.md", output_path)

    abbreviations_text = toc_lists.split("# List of Abbreviations", 1)[-1].strip()
    matches = list(re.finditer(r"([A-Z][A-Za-z0-9]+)\s+[–-]\s+", abbreviations_text))
    pairs: list[tuple[str, str]] = []
    for index, match in enumerate(matches):
        start = match.end()
        end = matches[index + 1].start() if index + 1 < len(matches) else len(abbreviations_text)
        meaning = abbreviations_text[start:end].strip()
        pairs.append((match.group(1), meaning))
    abbrev_lines = ["# List of Abbreviations", ""]
    for abbr, meaning in pairs:
        abbrev_lines.append(f"- **{abbr}**: {meaning.strip()}")

    return cleanup_spacing(
        "\n\n".join(
            [
                cover,
                ack,
                "## Table of Contents, List of Tables, and List of Figures\n\nThese items should be generated automatically after final formatting of the report.",
                "\n".join(abbrev_lines),
                abstract,
            ]
        )
    )


