def clean_dynamic_models_headings(text: str) -> str:
    replacements = {
        "1. User Management and Security": "##### 1. User Management and Security",
        "2. Patient and Caregiver Registration": "##### 2. Patient and Caregiver Registration",
        "3. Immunization and Surveillance Management": "##### 3. Immunization and Surveillance Management",
        "4. Notifications and Alerts": "##### 4. Notifications and Alerts",
        "5. Predictive Analytics and Decision Support": "##### 5. Predictive Analytics and Decision Support",
        "6. Reporting and Interoperability": "##### 6. Reporting and Interoperability",
        "1. User Account Lifecycle": "##### 1. User Account Lifecycle",
        "2. Patient Registration Flow": "##### 2. Patient Registration Flow",
        "3. Vaccination Appointment Lifecycle": "##### 3. Vaccination Appointment Lifecycle",
        "4. SMS Notification Flow": "##### 4. SMS Notification Flow",
        "5. Outbreak Alert Logic": "##### 5. Outbreak Alert Logic",
        "6. Data Export (Interoperability) Flow": "##### 6. Data Export (Interoperability) Flow",
        "1. Activity Diagram for User Management and Security": "##### 1. Activity Diagram for User Management and Security",
        "1. Activity Diagram for Patient and Caregiver Registration": "##### 2. Activity Diagram for Patient and Caregiver Registration",
        "1. Activity Diagram for Immunization and Surveillance Management": "##### 3. Activity Diagram for Immunization and Surveillance Management",
        "1. Activity Diagram for Notifications and Alerts": "##### 4. Activity Diagram for Notifications and Alerts",
        "1. Activity Diagram for Predictive Analytics and Decision Support": "##### 5. Activity Diagram for Predictive Analytics and Decision Support",
        "1. Activity Diagram for Reporting and Interoperability": "##### 6. Activity Diagram for Reporting and Interoperability",
    }
    for old, new in replacements.items():
        text = re.sub(rf"(?m)^{re.escape(old)}$", new, text)
    return text


def clean_chapter_three(draft_path: Path) -> str:
    parts = [
        read_for_draft("04-chapter-3-problem-analysis-and-modeling/chapter-source.md", draft_path),
        sectionize_source(read_for_draft("04-chapter-3-problem-analysis-and-modeling/01-existing-system-and-problems/report-source.md", draft_path)),
        sectionize_source(read_for_draft("04-chapter-3-problem-analysis-and-modeling/02-requirements-elicitation/report-source.md", draft_path)),
        sectionize_source(read_for_draft("04-chapter-3-problem-analysis-and-modeling/03-functional-requirements/report-source.md", draft_path)),
        sectionize_source(read_for_draft("04-chapter-3-problem-analysis-and-modeling/04-non-functional-requirements/report-source.md", draft_path)),
        sectionize_source(read_for_draft("04-chapter-3-problem-analysis-and-modeling/05-use-case-models/report-source.md", draft_path)),
        sectionize_source(read_for_draft("04-chapter-3-problem-analysis-and-modeling/06-dynamic-models/report-source.md", draft_path)),
        sectionize_source(read_for_draft("04-chapter-3-problem-analysis-and-modeling/07-model-validation/report-source.md", draft_path)),
    ]
    draft = "\n\n".join(parts)
    draft = clean_dynamic_models_headings(draft)
    draft = draft.replace("\n- Human actors who initiate actions or receive notifications:\n", "\n##### Human actors who initiate actions or receive notifications\n")
    draft = draft.replace("\n- System modules that process and store data:\n", "\n##### System modules that process and store data\n")
    draft = draft.replace("Report Generation Modul e", "Report Generation Module")
    draft = add_mermaid_links(draft, draft_path)
    return cleanup_spacing(draft)


def extract_er_diagram() -> str:
    db_design = read_markdown("05-chapter-4-system-design/04-database-design/NVOMS_DATABASE_DESIGN.md")
    match = re.search(r"```mermaid\n(.*?)```", db_design, re.DOTALL)
    if not match:
        return ""
    return "```mermaid\n" + match.group(1).strip() + "\n```"


def clean_chapter_four(draft_path: Path) -> str:
    chapter = """# Chapter Four: System Design

This chapter presents the detailed system design of the National Vaccination and Outbreak Monitoring System (NVOMS) for Ethiopia. The design translates the validated requirements and models from Chapter Three into a structured technical solution that supports secure data capture, vaccination tracking, predictive analytics, interoperability, and scalable public health decision support.
"""
    goals = sectionize_source(read_for_draft("05-chapter-4-system-design/01-overview-and-design-goals/report-source.md", draft_path))
    architecture = sectionize_source(read_for_draft("05-chapter-4-system-design/02-software-architecture/report-source.md", draft_path))
    subsystem = nest_standalone_doc(read_for_draft("05-chapter-4-system-design/04-database-design/NVOMS_SUBSYSTEM_DECOMPOSITION.md", draft_path))

    architecture = architecture.replace(
        "*Figure 4.0. System Architecture*",
        "*Figure 4.1: Layered Service-Oriented Architecture of the National Vaccination and Outbreak Monitoring System*",
    )
    architecture = architecture.replace("1. Architecture Overview (4-Tier Layered SOA)", "### Architecture Overview (4-Tier Layered SOA)")

    database_section = f"""## 4.3.3 Database Design

The database design of NVOMS is derived directly from the system requirements, the use-case model, the dynamic models, the layered service-oriented architecture, and the subsystem decomposition. PostgreSQL is selected as the core data platform because it provides strong relational integrity for vaccination tracking, support for structured interoperability payloads, and extensibility for analytical and geospatial data.

### Database Design Principles

- The patient registry remains the central point of the data model so that every vaccination, surveillance observation, and notification can be tied to a uniquely identified child.
- Vaccination schedules are stored separately from actual administered doses in order to support due, overdue, defaulter, catch-up, and administered states.
- Offline synchronization, SMS notification delivery, interoperability exchange logs, and audit trails are treated as first-class data structures rather than side effects.
- Prediction outputs and analytical summaries are separated from transactional tables so that reporting and risk scoring can scale without weakening core clinical integrity.
- Administrative geography is modeled hierarchically to support dashboards, hotspot analysis, and integration with national reporting structures.

### Core Entity Groups

- Geography and facility structure: administrative units and health facilities.
- Security and administration: users, roles, permissions, sessions, reset tokens, audit logs, and settings.
- Core registry: caregivers, patients, and duplicate review records.
- Immunization engine: vaccine definitions, EPI schedule versions and rules, patient schedules, vaccine batches, dose events, and schedule status history.
- Surveillance and alerts: surveillance reports, surveillance symptoms, and outbreak alerts.
- Notifications: message templates, SMS notifications, and notification attempts.
- Prediction and analytics: environmental observations, model registry, prediction runs, prediction scores, and defaulter clusters.
- Reporting and interoperability: report definitions, generated reports, integration jobs, DHIS2 sync records, and FHIR exchange logs.
- Offline sync: device registrations, sync batches, and sync batch items.

### High-Level ER View

{extract_er_diagram()}

### Database Design Artifacts

- Narrative database design: [NVOMS_DATABASE_DESIGN.md]({rel_link(draft_path, '05-chapter-4-system-design/04-database-design/NVOMS_DATABASE_DESIGN.md')})
- Implementation-ready PostgreSQL schema: [NVOMS_POSTGRESQL_SCHEMA.sql]({rel_link(draft_path, '05-chapter-4-system-design/04-database-design/NVOMS_POSTGRESQL_SCHEMA.sql')})
- Diagram-oriented DBML schema: [NVOMS_SCHEMA_DBML.dbml]({rel_link(draft_path, '05-chapter-4-system-design/04-database-design/NVOMS_SCHEMA_DBML.dbml')})
- Functional-requirements traceability: [NVOMS_REQUIREMENTS_VERIFICATION.md]({rel_link(draft_path, '05-chapter-4-system-design/04-database-design/NVOMS_REQUIREMENTS_VERIFICATION.md')})
"""

    design_verification = """## 4.4 Design Verification

The design was reviewed against the functional and non-functional requirements identified in Chapter Three. The resulting architecture and database structure support secure role-based access, atomic patient and caregiver registration, vaccination schedule generation, offline data capture and synchronization, SMS-based reminders, predictive analytics, interoperability with DHIS2 through FHIR-aligned mappings, and auditable reporting workflows. The design therefore satisfies the main operational needs of the proposed NVOMS prototype while remaining extensible for future national-scale deployment.
"""

    draft = "\n\n".join([chapter, goals, architecture, subsystem, database_section.strip(), design_verification.strip()])
    draft = draft.replace("SubSystem", "Subsystem")
    draft = add_mermaid_links(draft, draft_path)
    return cleanup_spacing(draft)


