def rewrite_links_for_build(text: str, source_path: Path) -> str:
    def replacer(match: re.Match[str]) -> str:
        target = match.group(1)
        if target.startswith(("http://", "https://", "#", "/")):
            return match.group(0)
        resolved = (source_path.parent / target).resolve()
        try:
            rewritten = resolved.relative_to(DOC_ROOT)
        except ValueError:
            return match.group(0)
        return f"]({(Path('..') / rewritten).as_posix()})"

    return re.sub(r"\]\(([^)]+)\)", replacer, text)


def generate_build_document(draft_paths: list[Path]) -> None:
    chunks = [
        "<!-- Combined submission-oriented draft generated from chapter draft files. -->",
        "",
        "# National Vaccination and Outbreak Monitoring System for Ethiopia",
        "",
    ]
    for path in draft_paths:
        text = path.read_text(encoding="utf-8")
        lines = text.splitlines()
        if lines and lines[0].startswith("<!-- Generated by documentation/tools/generate_chapter_drafts.py"):
            text = "\n".join(lines[2:]).strip()
        chunks.append(rewrite_links_for_build(text, path))
        chunks.append("")

    write_text(BUILD_DIR / "NVOMS_Submission_Draft.md", "\n".join(chunks))


def main() -> None:
    front_matter_path = DOC_ROOT / "01-front-matter/front-matter-draft.md"
    chapter_one_path = DOC_ROOT / "02-chapter-1-introduction/chapter-draft.md"
    chapter_two_path = DOC_ROOT / "03-chapter-2-literature-review/chapter-draft.md"
    chapter_three_path = DOC_ROOT / "04-chapter-3-problem-analysis-and-modeling/chapter-draft.md"
    chapter_four_path = DOC_ROOT / "05-chapter-4-system-design/chapter-draft.md"
    references_path = DOC_ROOT / "09-references/references-draft.md"

    write_text(front_matter_path, AUTO_NOTE + clean_front_matter())
    write_text(chapter_one_path, AUTO_NOTE + clean_chapter_one())
    write_text(chapter_two_path, AUTO_NOTE + clean_chapter_two())
    write_text(chapter_three_path, AUTO_NOTE + clean_chapter_three(chapter_three_path))
    write_text(chapter_four_path, AUTO_NOTE + clean_chapter_four(chapter_four_path))
    write_text(references_path, AUTO_NOTE + clean_references())

    generate_build_document(
        [
            front_matter_path,
            chapter_one_path,
            chapter_two_path,
            chapter_three_path,
            chapter_four_path,
            references_path,
        ]
    )


if __name__ == "__main__":
    main()
